cd /tmp && mkdir -p mstest-inspect && cat > mstest-inspect/Program.cs << 'CSHARP'
using System;
using System.Reflection;

var asm = Assembly.LoadFile("/home/runner/.nuget/packages/mstest.testframework/4.1.0/lib/net8.0/MSTest.TestFramework.dll");

foreach (var typeName in new[] { "Microsoft.VisualStudio.TestTools.UnitTesting.TestMethodAttribute", 
                                   "Microsoft.VisualStudio.TestTools.UnitTesting.TimeoutAttribute",
                                   "Microsoft.VisualStudio.TestTools.UnitTesting.TestTimeout" })
{
    var t = asm.GetType(typeName);
    if (t == null) { Console.WriteLine($"\n{typeName}: NOT FOUND"); continue; }
    Console.WriteLine($"\n=== {t.FullName} (sealed={t.IsSealed}, abstract={t.IsAbstract}) ===");
    foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
    {
        var pars = string.Join(", ", Array.ConvertAll(m.GetParameters(), p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  {(m.IsVirtual?"virtual ":"")}{m.ReturnType.Name} {m.Name}({pars})");
    }
    foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
        Console.WriteLine($"  prop {p.PropertyType.Name} {p.Name}");
    foreach (var c in t.GetConstructors())
    {
        var pars = string.Join(", ", Array.ConvertAll(c.GetParameters(), p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  ctor({pars})");
    }
    // check enums
    if (t.IsEnum)
        foreach (var v in Enum.GetNames(t))
            Console.WriteLine($"  {v} = {(int)Enum.Parse(t, v)}");
}
CSHARP

